<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
                <div role="document" class="modal-dialog" style="max-width: 1300px !important;">
                    <div class="modal-content">
                        <div
                            class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">
                                {{ refCode === 'Update' ? $t('UpdateLimit') : $t('AddLimit') }}
                            </h5>
                            <button type="button" class="close" @click="CloseLimit">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                            <span class="user-guide">
                                <a class="ancuserguide text-white" data-toggle="collapse" href="javascript:;" role="button" aria-expanded="false" aria-controls="collapseExample">
                                    <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}
                                </a>
                                <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                    <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                        <div class="con"  v-html="getUserGuideTitle()"></div>
                                    </div>
                                </div>
                            </span>
                        </div>

                        <div class="modal-body">
                            <dynamic-form lang="en" ref="validateLimit" :buttons="buttons" :schema="FormSchema"
                                :mandatorytext="$t('MandatoryString')">
                                <template v-slot:tgslot-Limit="{ data }">


                                    <Field name="Limit" :rules="{ 'required': true }" v-slot="{ errors }">
                                        <div class="input-group">
                                            <input type="number" id="" v-model="data.fieldInfo.value" min="1"
                                                maxlength="365" v-bind:class="{ 'txtitems form-control ': true, }" />
                                        </div>
                                        <span v-if="errors[0]" name="Limit" class="invalid-feedback d-block">{{
                                            errors[0]
                                            }}</span>

                                    </Field>
                                </template>
                                <template v-slot:tgslot-DayLimit="{ data }">


                                    <Field name="DayLimit" :rules="{ 'required': true }" v-slot="{ errors }">
                                        <div class="input-group">
                                            <input type="number" id="" v-model="data.fieldInfo.value" min="1"
                                                maxlength="365" v-bind:class="{ 'txtitems form-control ': true, }" />

                                        </div>
                                        <span v-if="errors[0]" name="DayLimit" class="invalid-feedback d-block">{{
                                            errors[0]
                                            }}</span>

                                    </Field>
                                </template>
                            </dynamic-form>
                        </div>

                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import { placeholder } from '@mapbox/mapbox-gl-geocoder/lib/localization';
import DataService from '../../../services/DataService';
import {
    locateBillingService
} from "../../../services/locateBillingService";


export default {
    props: {
        callbackfunction: {
            type: Function,
            required: false
        },
        refCode: {
            type: String,
            required: false
        },
        EditLimitData: {
            type: Object,
            required: false
        },
        configurationId: {
            type: String,
            required: false
        },
        clientId:{
            type: Number,
            required: false
        },
        mode: {
            type: String,
            default: 'Edit'
        }
    },
    data() {

        return {
            isLoading: false,
            id: 0,
            isVisibleUtility: true,
            clientsIds: '',
            type: "",
            isShown: false,
            FormSchema: [
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SelectField",
                            label: this.$t('WorkCode'),
                            name: "WorkCode",
                            value: "",
                            placeholder: this.$t('Select'),
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('AlternateWorkCode'),
                            name: "AlternateWorkcode",
                            value: "",
                            visibility: true,
                            config: {
                                options: [],
                            },
                            placeholder: this.$t('Select'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SlotField",
                            label: this.$t('LimitValue'),
                            name: "Limit",
                            value: "",
                            placeholder: '',
                            validationRules: { "required": false, max: 365 },
                            visibility: true,
                        }

                    ]
                },
                {
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SlotField",
                            label: this.$t('DayLimit'),
                            name: "DayLimit",
                            value: "",
                            placeholder: '',
                            validationRules: { "required": false, max: 365 },
                            visibility: true,
                        },
                        {
                            astype: "toggleField",
                            label: this.$t('IsApplicableToAll'),
                            name: "ApplicableToAll",
                            visibility: true,
                            disabled: false,
                            value: "",
                            config: {
                                options: [{ value: "1", name: this.$t('Yes') }, { value: "0", name: this.$t('No') }],
                                onChange: this.onChangeApplicable
                            }

                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: { selectAll: true,  clear: true },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": true
                            },
                        }
                        // {
                        //     astype: "SelectField",
                        //     label: this.$t('UtilityName'),
                        //     name: "UtilityName",
                        //     value: "",
                        //     visibility: true,
                        //     config: {
                        //         options: [],
                        //     },
                        //     placeholder: this.$t('Select'),
                        //     validationRules: { "required": true, max: 100 },
                        //     settings: {
                        //         isInSlot: true
                        //     }
                        // },
                    ]
                },

            ],
        }
    },
    computed: {
        buttons() {
            const baseButtons = [
                {
                    type: "submit",
                    class: "btn btn-success",
                    visibility: true,
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('SaveAndClose'),
                    onClick: this.SubmitData,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save'),
                    onClick: this.SubmitData
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.CloseLimit,
                },
            ];
            
            // Hide Save buttons when mode is View - filter out submit buttons
            if (this.mode === 'View') {
                return baseButtons.filter(btn => btn.type !== 'submit');
            }
            
            return baseButtons;
        }
    },
    created: async function () {
        var vm = this;
        await vm.GetDdlWorkCode();
        await vm.GetUtilityList();
    },
    mounted() {
        if (this.EditLimitData && Object.keys(this.EditLimitData).length > 0 && this.refCode == 'Update') {
            this.BindEditDetail(this.EditLimitData);
        }
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  // adds .show ? triggers transform transition
            }, 50);
        });
    },
    methods: {
        getUserGuideTitle() {
            let text = this.$t('UserGuide_billing_limit_Add');
            return text
                // 🔥 IMPORTANT: escaped characters
                .replace(/\\n/g, '')
                .replace(/\\t/g, '&nbsp;');
        },
        BindEditDetail: function(data) {
            var vm = this;
            vm.id = data.limitId;
            vm.configurationId != null ? vm.configurationId : 0;
            vm.$refs.validateLimit.updateProperty("WorkCode", "value", data.workCodeId);
            vm.$refs.validateLimit.updateProperty("AlternateWorkcode", "value", data.alternateWorkCodeId);
            vm.$refs.validateLimit.updateProperty("Limit", "value", data.limitValue);
            vm.$refs.validateLimit.updateProperty("DayLimit", "value", data.dayLimit);
            vm.$refs.validateLimit.updateProperty("ApplicableToAll", "value", data.isApplicableToAll);
            var isapplicable = vm.$refs.validateLimit.getPropertyValue("ApplicableToAll", "value", data.isApplicableToAll);
            if (isapplicable) {
                vm.$refs.validateLimit.updateProperty("UtilityName", "visibility", false);
                vm.$refs.validateLimit.updateProperty("UtilityName", "validationRules", false);
            }
            vm.$refs.validateLimit.updateProperty("UtilityName", "value", data.clientLimitId);
            vm.$refs.validateLimit.UpdateKeyValue();
        },
        GetDdlWorkCode: async function () {
            var vm = this;
            vm.isLoading = true;
            await DataService.GetWorkCodeInfo().then((response) => {
                if (response.data != '' && response.data != null) {
                    var selctedValue = [];
                    if (response.data.length > 0) {
                        response.data.forEach((item, index) => {
                            selctedValue.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                    }
                    vm.$refs.validateLimit.updateProperty("WorkCode", "config.options", selctedValue);
                    vm.$refs.validateLimit.updateProperty("AlternateWorkcode", "config.options", selctedValue);
                    vm.$refs.validateLimit.UpdateKeyValue();
                }
            });
            vm.isLoading = false;
        },
        GetUtilityList: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `clientId=${vm.clientId}&configId=${vm.configurationId != null ? vm.configurationId : 0}&reqFrom=&clientIds=`;
            await locateBillingService.getUtilityList(url).then(response => {
                vm.isLoading = false;
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.$refs.validateLimit.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                    vm.$refs.validateLimit.UpdateKeyValue();
                    //this.FormSchema[1].Data[2].config.options=SelectedUtilityList;
                }
            }).catch(error => {
                vm.isLoading = false;
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        onChangeApplicable() {
            var utilityselectval = this.$refs.validateLimit.getPropertyValue("ApplicableToAll", "value");
            switch (utilityselectval) {
                case true:
                    this.$refs.validateLimit.updateProperty("UtilityName", "visibility", false);
                    this.$refs.validateLimit.updateProperty("UtilityName", "validationRules.required", false);
                    this.$refs.validateLimit.updateProperty("UtilityName", "value", "");
                    break;
                default:
                    this.$refs.validateLimit.updateProperty("UtilityName", "visibility", true);
                    this.$refs.validateLimit.updateProperty("UtilityName", "validationRules.required", true);
            }

        },
        SubmitData: async function (event) {
            var vm = this;
            vm.isLoading = true;
            const result = await vm.$refs.validateLimit.validateForm.validate();
            if (!result) {
                this.isLoading = false;
                return;
            }
            var chkutilityvalidation = vm.$refs.validateLimit.getPropertyValue("ApplicableToAll", "value");
            var selectedutility = vm.$refs.validateLimit.getPropertyValue("UtilityName", "value");
            if (result == true && chkutilityvalidation === false && selectedutility == "") {
                vm.$refs.validateLimit.updateProperty("UtilityName", "validationRules", true);
                vm.isLoading = false;
                return;
            }
            const limitId = vm.id == 0 ? 0 : vm.id;
            const ConfigId = vm.configurationId != null ? vm.configurationId : 0;
            const WorkCodeId = vm.$refs.validateLimit.getPropertyValue("WorkCode", "value");
            const AlternateWorkCodeId = vm.$refs.validateLimit.getPropertyValue("AlternateWorkcode", "value");
            const LimitValue = vm.$refs.validateLimit.getPropertyValue("Limit", "value");
            const DayLimit = vm.$refs.validateLimit.getPropertyValue("DayLimit", "value");
            const IsApplicableToAll = vm.$refs.validateLimit.getPropertyValue("ApplicableToAll", "value");
            const utility_id = IsApplicableToAll == true ? vm.clientId : selectedutility[0];
            const client_limit_name = vm.$refs.validateLimit.getPropertyValue("UtilityName", "value");
            var obj = {
                limitId: limitId,
                client_id : vm.clientId,
                configuration_id: ConfigId,
                workcode_id: WorkCodeId,
                alternate_code: AlternateWorkCodeId,
                limit: LimitValue,
                limit_days: DayLimit,
                is_applicable_to_all: IsApplicableToAll,
                utility_id: utility_id,
                client_limit_name : Array.isArray(client_limit_name) && client_limit_name.length ? client_limit_name.join(',') : null
            }
            var jsondata = JSON.stringify(obj);
            var url = `Data=${jsondata}`;
            await DataService.CreateLimit(url).then((response) => {
                if (response.data != '') {
                    if (response.data[0].STATUS_CODE == 1 && vm.id == 0) {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('LimitValue')]), "Success", true, vm.$t('Alert'));
                        vm.callbackfunction();
                        vm.ResetModel();
                        vm.CloseLimit();

                    }
                    else if (response.data[0].STATUS_CODE == 1 && vm.id > 0) {
                        vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('LimitValue')]), "Success", true, vm.$t('Alert'))
                        vm.callbackfunction();
                        vm.CloseLimit();

                    }
                    else {
                        vm.ShowAlert(vm.$t("ErrorWhileSaving", [vm.$t("LimitValue")]), "danger", true, vm.$t("Alert"));
                    }
                }
                vm.isLoading = false;
            });
        },
        ResetModel() {
            var vm = this;
            const id = 0;
            vm.$refs.validateLimit.updateProperty("WorkCode", "value", "");
            vm.$refs.validateLimit.updateProperty("AlternateWorkcode", "value", "");
            vm.$refs.validateLimit.updateProperty("Limit", "value", "");
            vm.$refs.validateLimit.updateProperty("DayLimit", "value", "");
            vm.$refs.validateLimit.updateProperty("ApplicableToAll", "value", "");
            vm.$refs.validateLimit.updateProperty("UtilityName", "value", "");
        },
        CloseLimit() {
            this.$emit('CloseLimit');
        },
    },
}
</script>

<style lang="scss" scoped></style>